// Validate the rerun request.
// Expects: { topic_slug, date_key, alert_ids? }
// alert_ids is optional — if omitted, retries all undelivered alerts for the topic/date.
const body = $input.first().json.body || $input.first().json;
const topic_slug = body.topic_slug;
const date_key = body.date_key;
const alert_ids = body.alert_ids || null;

if (!topic_slug || !date_key) {
  throw new Error('Missing required fields: topic_slug and date_key');
}

return [{ json: { topic_slug, date_key, alert_ids, execution_id: $execution.id } }];

