={{ JSON.stringify((() => {
  const ctx = $json;
  const alertIds = ctx.alert_ids;
  if (alertIds && Array.isArray(alertIds) && alertIds.length > 0) {
    const placeholders = alertIds.map(() => '?').join(', ');
    return {
      sql: "SELECT id, topic_slug, date_key, headline, summary_text, source_url, source_name, severity_score, importance_score, event_at, delivered_telegram, delivered_discord, metadata_json FROM alerts WHERE topic_slug = ? AND date_key = ? AND status = 'active' AND (delivered_telegram = 0 OR delivered_discord = 0) AND id IN (" + placeholders + ") ORDER BY event_at ASC",
      params: [ctx.topic_slug, ctx.date_key, ...alertIds]
    };
  }
  return {
    sql: "SELECT id, topic_slug, date_key, headline, summary_text, source_url, source_name, severity_score, importance_score, event_at, delivered_telegram, delivered_discord, metadata_json FROM alerts WHERE topic_slug = ? AND date_key = ? AND status = 'active' AND (delivered_telegram = 0 OR delivered_discord = 0) ORDER BY event_at ASC LIMIT 50",
    params: [ctx.topic_slug, ctx.date_key]
  };
})()) }}

