const resp = $input.first().json;
const rows = resp?.result?.[0]?.results || [];
const ctx = $('Extract Rerun ID').first().json;

// If specific alert_ids were requested but not all were in the query result
// (due to LIMIT), we already used an ID-targeted query so all matches are here.
let filtered = rows;

if (filtered.length === 0) {
  return [{ json: { ...ctx, _skip: true, skip_reason: 'No undelivered alerts found.' } }];
}

const items = filtered.map(row => {
  let meta = {};
  try { meta = typeof row.metadata_json === 'string' ? JSON.parse(row.metadata_json) : (row.metadata_json || {}); } catch(e) {}
  const channels = [];
  if (!row.delivered_telegram) channels.push('telegram');
  if (!row.delivered_discord) channels.push('discord');
  return {
    alert_id: row.id,
    item_id: meta.item_id || null,
    topic_slug: row.topic_slug,
    date_key: row.date_key,
    headline: row.headline,
    summary_text: row.summary_text,
    source_url: row.source_url,
    source_name: row.source_name,
    severity_score: row.severity_score,
    importance_score: row.importance_score,
    event_at: row.event_at,
    channels
  };
});

return [{ json: { ...ctx, _skip: false, items, retry_count: items.length } }];

const tgResult = $('Retry Telegram Delivery').first()?.json || {};
const dcResult = $('Retry Discord Delivery').first()?.json || {};
const ctx = $('Build Retry Payloads').first().json;
const allOk = !tgResult.error && !dcResult.error;
const errors = [];
if (tgResult.error) errors.push('Telegram: ' + (tgResult.error.message || 'failed'));
if (dcResult.error) errors.push('Discord: ' + (dcResult.error.message || 'failed'));

return [{ json: {
  rerun_id: ctx.rerun_id,
  final_status: allOk ? 'success' : 'failed',
  error_message: allOk ? null : errors.join('; ')
} }];

